queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?issue_name ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:issue_id ?cg . ?child a :Issues ; p:id ?cg . ?l p:patient_advocate_id ?pg . ?parent a :Patient_Advocates ; p:id ?pg . } GROUP BY ?child }
  ?child p:issue_name ?issue_name .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Patient_Advocates } }
  FILTER(?nf = ?total)
}

